#include <string>
#include <vector>
#include <algorithm>

using namespace std;

string solve(string s) {
    vector<char> result;

    for (char c : s) {
        if (islower(c)) {
            result.push_back(c);
        } else if (c == '*') {
            if (!result.empty()) {
                result.pop_back();
            }
        } else if (c == '#') {
            result.insert(result.end(), result.begin(), result.end());
        } else if (c == '%') {
            reverse(result.begin(), result.end());
        }
    }

    string output;
    for (char c : result) {
        output += c;
    }
    return output;
}
